import{_ as d,o as r,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"天道系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tiandao.md","filePath":"guide/tiandao.md","lastUpdated":null}'),e={name:"guide/tiandao.md"};function h(l,t,n,s,i,b){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="天道系统" tabindex="-1">天道系统 <a class="header-anchor" href="#天道系统" aria-label="Permalink to &quot;天道系统&quot;">​</a></h1><p>天道系统是修仙服务器的<strong>善恶/功德</strong>机制。积德行善可获得功德值，提升天道境界，享受各种增益。反之，恶意行为会受到天道惩罚。</p><hr><h2 id="天道境界" tabindex="-1">天道境界 <a class="header-anchor" href="#天道境界" aria-label="Permalink to &quot;天道境界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>境界</th><th>功德阈值</th><th>突破加成</th><th>渡劫减伤</th><th>灵气倍率</th><th>功法倍率</th><th>商店折扣</th></tr></thead><tbody><tr><td><strong>普通人</strong></td><td>0</td><td>+0%</td><td>0%</td><td>×1.0</td><td>×1.0</td><td>0%</td></tr><tr><td><strong>有德</strong></td><td>100</td><td>+2%</td><td>0%</td><td>×1.0</td><td>×1.0</td><td>0%</td></tr><tr><td><strong>积善</strong></td><td>300</td><td>+4%</td><td>10%</td><td>×1.1</td><td>×1.0</td><td>5%</td></tr><tr><td><strong>天道眷顾</strong></td><td>600</td><td>+6%</td><td>20%</td><td>×1.2</td><td>×1.1</td><td>10%</td></tr><tr><td><strong>代天行道</strong></td><td>1,000</td><td>+8%</td><td>30%</td><td>×1.3</td><td>×1.15</td><td>15%</td></tr><tr><td><strong>天人合一</strong></td><td>1,500</td><td>+10%</td><td>40%</td><td>×1.5</td><td>×1.2</td><td>20%</td></tr></tbody></table><blockquote><p>🌟 天道境界越高，突破越容易、渡劫越安全、灵气恢复越快、天道商店越便宜！</p></blockquote><hr><h2 id="功德获取方式" tabindex="-1">功德获取方式 <a class="header-anchor" href="#功德获取方式" aria-label="Permalink to &quot;功德获取方式&quot;">​</a></h2><h3 id="正面获取-功德" tabindex="-1">正面获取（+功德） <a class="header-anchor" href="#正面获取-功德" aria-label="Permalink to &quot;正面获取（+功德）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行为</th><th>功德</th><th>说明</th></tr></thead><tbody><tr><td>🏆 Boss服务器首杀</td><td>+100</td><td>全服第一个击杀该Boss</td></tr><tr><td>🎯 Boss个人首杀</td><td>+50</td><td>个人首次击杀该Boss</td></tr><tr><td>⬆️ 大境界突破</td><td>+30</td><td>每次成功突破大境界</td></tr><tr><td>🚀 飞升</td><td>+200</td><td>达到飞升境界</td></tr><tr><td>⚡ 渡劫成功</td><td>+50</td><td>每次成功渡劫</td></tr><tr><td>🤝 带新人打Boss</td><td>+20/人</td><td>带低境界玩家击杀Boss</td></tr><tr><td>🛡️ 连续失败保护触发</td><td>+10</td><td>突破连续失败3次后触发</td></tr><tr><td>⚔️ 决斗胜利</td><td>+5</td><td>每次决斗获胜</td></tr><tr><td>💊 炼丹极品</td><td>+15</td><td>炼制出极品品质丹药</td></tr></tbody></table><h4 id="带新人条件" tabindex="-1">带新人条件 <a class="header-anchor" href="#带新人条件" aria-label="Permalink to &quot;带新人条件&quot;">​</a></h4><ul><li>境界差 ≥ <strong>2个大境界</strong></li><li>带每位新人击杀Boss额外获得 20 功德</li></ul><h3 id="负面扣减-功德" tabindex="-1">负面扣减（-功德） <a class="header-anchor" href="#负面扣减-功德" aria-label="Permalink to &quot;负面扣减（-功德）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行为</th><th>惩罚</th><th>说明</th></tr></thead><tbody><tr><td>😈 恶意击杀</td><td><strong>-200</strong></td><td>击杀低于自己2个大境界以上的玩家</td></tr></tbody></table><hr><h2 id="天道商店" tabindex="-1">天道商店 <a class="header-anchor" href="#天道商店" aria-label="Permalink to &quot;天道商店&quot;">​</a></h2><p>消耗功德值兑换稀有物品：</p><table tabindex="0"><thead><tr><th>商品</th><th>功德价</th><th>限购</th><th>说明</th></tr></thead><tbody><tr><td>突破丹（中等）</td><td>30</td><td>每日5个</td><td>突破成功率 +30%</td></tr><tr><td>渡劫丹（中等）</td><td>50</td><td>每日3个</td><td>渡劫成功率 +25%</td></tr><tr><td>天道灵石</td><td>100</td><td>每日1个</td><td>稀有强化材料</td></tr><tr><td>功德护符</td><td>200</td><td>每周1个</td><td>护身法宝</td></tr><tr><td>天劫令</td><td>500</td><td>每月1个</td><td>特殊道具</td></tr><tr><td>功德宝箱</td><td>300</td><td>每周3个</td><td>随机奖励宝箱</td></tr></tbody></table><blockquote><p>💡 天道境界越高，商店享受的折扣越大（天人合一可享 20% off！）</p></blockquote><hr><h2 id="天道事件" tabindex="-1">天道事件 <a class="header-anchor" href="#天道事件" aria-label="Permalink to &quot;天道事件&quot;">​</a></h2><p>天道会随机触发全服事件，影响所有在线玩家：</p><h3 id="灵气潮汐-🌊" tabindex="-1">灵气潮汐 🌊 <a class="header-anchor" href="#灵气潮汐-🌊" aria-label="Permalink to &quot;灵气潮汐 🌊&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>值</th></tr></thead><tbody><tr><td>触发权重</td><td>30（相对权重，较常见）</td></tr><tr><td>持续时间</td><td>30分钟</td></tr><tr><td>灵气恢复倍率</td><td><strong>×2.0</strong></td></tr><tr><td>修炼灵气倍率</td><td><strong>×1.5</strong></td></tr><tr><td>突破成功率加成</td><td>+0%</td></tr><tr><td>突破冷却减半</td><td>❌</td></tr><tr><td>渡劫伤害倍率</td><td>×1.0</td></tr><tr><td>击杀功德倍率</td><td>×1.0</td></tr></tbody></table><p><strong>开场广播</strong>：【天道】灵气潮汐涌动，天地灵机大盛！</p><p><strong>结束广播</strong>：【天道】灵气潮汐渐息。</p><blockquote><p>🌊 灵气潮汐是修炼的最佳时机！灵气恢复翻倍+修炼效率×1.5，配合修炼丹效果更佳。</p></blockquote><h3 id="天道试炼-⚡" tabindex="-1">天道试炼 ⚡ <a class="header-anchor" href="#天道试炼-⚡" aria-label="Permalink to &quot;天道试炼 ⚡&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>值</th></tr></thead><tbody><tr><td>触发权重</td><td>20（相对权重）</td></tr><tr><td>持续时间</td><td>30分钟</td></tr><tr><td>灵气恢复倍率</td><td>×1.0</td></tr><tr><td>修炼灵气倍率</td><td>×1.0</td></tr><tr><td>突破成功率加成</td><td><strong>+15%</strong></td></tr><tr><td>突破冷却减半</td><td>✅ <strong>是</strong></td></tr><tr><td>渡劫伤害倍率</td><td><strong>×0.8</strong>（减免20%）</td></tr><tr><td>击杀功德倍率</td><td>×1.0</td></tr></tbody></table><p><strong>开场广播</strong>：【天道】试炼开启，突破屏障暂时松动。</p><p><strong>结束广播</strong>：【天道】试炼结束，天机复归。</p><blockquote><p>🎯 天道试炼是突破的最佳时机！+15%成功率、冷却减半、渡劫减伤20%——三重利好叠加！</p></blockquote><h3 id="事件触发机制" tabindex="-1">事件触发机制 <a class="header-anchor" href="#事件触发机制" aria-label="Permalink to &quot;事件触发机制&quot;">​</a></h3><ul><li><strong>随机间隔</strong>：120分钟～360分钟（2~6小时）</li><li><strong>全服广播</strong>：所有玩家可见</li><li><strong>事件随机</strong>：灵气潮汐（权重30）vs 天道试炼（权重20）</li></ul><hr><h2 id="功德衰减" tabindex="-1">功德衰减 <a class="header-anchor" href="#功德衰减" aria-label="Permalink to &quot;功德衰减&quot;">​</a></h2><p>如果玩家长时间不活跃，功德值会逐渐衰减：</p><ul><li><strong>衰减启用</strong>：✅ 是</li><li><strong>不活跃天数</strong>：7天</li><li><strong>衰减比例</strong>：每日衰减当前功德的 5%</li></ul><blockquote><p>⚠️ 超过7天不登录，功德值开始每日递减。保持活跃才能维持天道境界！</p></blockquote><hr><h2 id="天道广播" tabindex="-1">天道广播 <a class="header-anchor" href="#天道广播" aria-label="Permalink to &quot;天道广播&quot;">​</a></h2><p>当玩家天道境界晋升时，全服广播祝贺：</p><blockquote><p>【天道】 {Player} 功德圆满，晋升 {TierName}！</p></blockquote><hr><h2 id="天道策略建议" tabindex="-1">天道策略建议 <a class="header-anchor" href="#天道策略建议" aria-label="Permalink to &quot;天道策略建议&quot;">​</a></h2><h3 id="快速提升天道境界" tabindex="-1">快速提升天道境界 <a class="header-anchor" href="#快速提升天道境界" aria-label="Permalink to &quot;快速提升天道境界&quot;">​</a></h3><ol><li><strong>优先击杀Boss</strong> — 首杀奖励最多（个人+50，服务器首杀+100）</li><li><strong>组队带新人</strong> — 带低境界玩家打Boss，每人 +20</li><li><strong>积极突破</strong> — 每次大境界突破 +30</li><li><strong>参与决斗</strong> — 胜利 +5，积少成多</li><li><strong>炼制极品丹药</strong> — 每次成功 +15</li></ol><h3 id="避免功德惩罚" tabindex="-1">避免功德惩罚 <a class="header-anchor" href="#避免功德惩罚" aria-label="Permalink to &quot;避免功德惩罚&quot;">​</a></h3><ul><li>❌ <strong>不要击杀低境界玩家</strong> — 境界差 ≥ 2 即触发 -200 惩罚</li><li>✅ 同境界或更高境界的PVP不受惩罚</li></ul>',49)])])}const c=d(e,[["render",h]]);export{u as __pageData,c as default};
